import{_ as n,c as t,o as i,a1 as s}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Tool-Suite: Speicher steuern | opencode-supermemory","description":"Meistern Sie die 5 Kernmodi des supermemory-Tools (add, search, profile, list, forget) und steuern Sie das Speicherverhalten durch natürliche Sprache.","frontmatter":{"title":"Tool-Suite: Speicher steuern | opencode-supermemory","sidebarTitle":"Tool-Suite","subtitle":"Tool-Suite: Den Agenten Speichern lehren","description":"Meistern Sie die 5 Kernmodi des supermemory-Tools (add, search, profile, list, forget) und steuern Sie das Speicherverhalten durch natürliche Sprache.","tags":["Tool-Verwendung","Speichermanagement","Kernfunktionen"],"prerequisite":["start-getting-started"],"order":2},"headers":[],"relativePath":"de/supermemoryai/opencode-supermemory/core/tools/index.md","filePath":"de/supermemoryai/opencode-supermemory/core/tools/index.md"}'),r={name:"de/supermemoryai/opencode-supermemory/core/tools/index.md"};function a(o,e,l,h,d,p){return i(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="tool-suite-detaillierung-den-agenten-speichern-lehren" tabindex="-1">Tool-Suite-Detaillierung: Den Agenten Speichern lehren <a class="header-anchor" href="#tool-suite-detaillierung-den-agenten-speichern-lehren" aria-label="Permalink to &quot;Tool-Suite-Detaillierung: Den Agenten Speichern lehren&quot;">​</a></h1><h2 id="was-sie-nach-dieser-lektion-konnen" tabindex="-1">Was Sie nach dieser Lektion können <a class="header-anchor" href="#was-sie-nach-dieser-lektion-konnen" aria-label="Permalink to &quot;Was Sie nach dieser Lektion können&quot;">​</a></h2><p>In dieser Lektion meistern Sie die Kerninteraktionsmethode des <code>supermemory</code>-Plugins. Obwohl der Agent normalerweise Speicher automatisch verwaltet, müssen Sie als Entwickler oft manuell eingreifen.</p><p>Nach dieser Lektion können Sie:</p><ol><li>Verwenden Sie den <code>add</code>-Modus, um wichtige technische Entscheidungen manuell zu speichern.</li><li>Verwenden Sie den <code>search</code>-Modus, um zu verifizieren, ob der Agent Ihre Präferenzen gespeichert hat.</li><li>Verwenden Sie <code>profile</code>, um zu sehen, wie der Agent &quot;Sie&quot; sieht.</li><li>Verwenden Sie <code>list</code> und <code>forget</code>, um veraltete oder fehlerhafte Speicher zu bereinigen.</li></ol><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><p>opencode-supermemory ist keine Black Box; es interagiert mit dem Agenten über das Standard-OpenCode-Tool-Protokoll. Das bedeutet, Sie können es wie eine Funktion aufrufen oder den Agenten durch natürliche Sprache anweisen, es zu verwenden.</p><p>Das Plugin registriert ein Tool namens <code>supermemory</code> beim Agenten, das wie ein Schweizer Taschenmesser mit 6 Modi ist:</p><table tabindex="0"><thead><tr><th>Modus</th><th>Funktion</th><th>Typisches Szenario</th></tr></thead><tbody><tr><td><strong>add</strong></td><td>Speicher hinzufügen</td><td>&quot;Merken Sie sich, dieses Projekt muss mit Bun laufen&quot;</td></tr><tr><td><strong>search</strong></td><td>Speicher suchen</td><td>&quot;Habe ich vorher gesagt, wie man Authentifizierung behandelt?&quot;</td></tr><tr><td><strong>profile</strong></td><td>Benutzerprofil</td><td>Zeigen Sie die Codierungsgewohnheiten, die der Agent über Sie zusammengefasst hat</td></tr><tr><td><strong>list</strong></td><td>Speicher auflisten</td><td>Überprüfen Sie die zuletzt gespeicherten 10 Speicher</td></tr><tr><td><strong>forget</strong></td><td>Speicher löschen</td><td>Löschen Sie einen fehlerhaften Konfigurationsdatensatz</td></tr><tr><td><strong>help</strong></td><td>Benutzerhandbuch</td><td>Zeigen Sie die Tool-Hilfedokumentation an</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Automatischer Auslösemechanismus</p><p>Neben dem manuellen Aufruf überwacht das Plugin auch Ihren Chat-Inhalt. Wenn Sie durch natürliche Sprache &quot;Remember this&quot; oder &quot;Save this&quot; sagen, erkennt das Plugin automatisch die Schlüsselwörter und zwingt den Agenten, das <code>add</code>-Tool aufzurufen.</p></div><h2 id="fuhren-sie-es-mit-mir-aus-speicher-manuell-verwalten" tabindex="-1">Führen Sie es mit mir aus: Speicher manuell verwalten <a class="header-anchor" href="#fuhren-sie-es-mit-mir-aus-speicher-manuell-verwalten" aria-label="Permalink to &quot;Führen Sie es mit mir aus: Speicher manuell verwalten&quot;">​</a></h2><p>Obwohl wir normalerweise den Agenten automatisch agieren lassen, ist der manuelle Aufruf von Tools beim Debuggen oder Aufbau des initialen Speichers sehr nützlich. Sie können den Agenten im OpenCode-Dialogfenster direkt durch natürliche Sprache anweisen, diese Operationen auszuführen.</p><h3 id="_1-speicher-hinzufugen-add" tabindex="-1">1. Speicher hinzufügen (Add) <a class="header-anchor" href="#_1-speicher-hinzufugen-add" aria-label="Permalink to &quot;1. Speicher hinzufügen (Add)&quot;">​</a></h3><p>Dies ist die am häufigsten verwendete Funktion. Sie können den Inhalt, Typ und Umfang des Speichers angeben.</p><p><strong>Operation</strong>: Weisen Sie den Agenten an, einen Speicher über die Projektarchitektur zu speichern.</p><p><strong>Eingabebefehl</strong>:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Verwenden Sie das supermemory-Tool, um einen Speicher zu speichern:</span></span>
<span class="line"><span>Inhalt: &quot;Alle Service-Schicht-Codes dieses Projekts müssen im Verzeichnis src/services abgelegt werden&quot;</span></span>
<span class="line"><span>Typ: architecture</span></span>
<span class="line"><span>Umfang: project</span></span></code></pre></div><p><strong>Interne Verhalten des Agenten</strong> (Quellcode-Logik):</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;supermemory&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;args&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;mode&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;add&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;content&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Alle Service-Schicht-Codes dieses Projekts müssen im Verzeichnis src/services abgelegt werden&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;architecture&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;scope&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;project&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Was Sie sehen sollten</strong>: Der Agent gibt eine ähnliche Bestätigung zurück:</p><blockquote><p>✅ Memory added to project scope (ID: mem_12345...)</p></blockquote><div class="tip custom-block"><p class="custom-block-title">Auswahl des Speichertyps (Type)</p><p>Um die Suche präziser zu machen, empfehle ich, genaue Typen zu verwenden:</p><ul><li><code>project-config</code>: Tech-Stack, Toolchain-Konfiguration</li><li><code>architecture</code>: Architekturmuster, Verzeichnisstruktur</li><li><code>preference</code>: Ihre persönlichen Codierungspräferenzen (z. B. &quot;bevorzugt Pfeilfunktionen&quot;)</li><li><code>error-solution</code>: Spezifische Lösung für einen bestimmten Fehler</li><li><code>learned-pattern</code>: Vom Agenten beobachtete Codemuster</li></ul></div><h3 id="_2-speicher-suchen-search" tabindex="-1">2. Speicher suchen (Search) <a class="header-anchor" href="#_2-speicher-suchen-search" aria-label="Permalink to &quot;2. Speicher suchen (Search)&quot;">​</a></h3><p>Wenn Sie verifizieren möchten, ob der Agent etwas &quot;weißt&quot;, können Sie die Suchfunktion verwenden.</p><p><strong>Operation</strong>: Suchen Sie nach Speichern über &quot;Service-Schicht&quot;.</p><p><strong>Eingabebefehl</strong>:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Fragen Sie supermemory ab, das Schlüsselwort ist &quot;services&quot;, der Umfang ist project</span></span></code></pre></div><p><strong>Interne Verhalten des Agenten</strong>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;supermemory&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;args&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;mode&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;search&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;query&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;services&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;scope&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;project&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Was Sie sehen sollten</strong>: Der Agent listet relevante Speicherfragmente und ihre Ähnlichkeit (Similarity) auf.</p><h3 id="_3-benutzerprofil-anzeigen-profile" tabindex="-1">3. Benutzerprofil anzeigen (Profile) <a class="header-anchor" href="#_3-benutzerprofil-anzeigen-profile" aria-label="Permalink to &quot;3. Benutzerprofil anzeigen (Profile)&quot;">​</a></h3><p>Supermemory unterhält automatisch ein &quot;Benutzerprofil&quot;, das Ihre langfristigen Präferenzen enthält.</p><p><strong>Operation</strong>: Sehen Sie Ihr Profil an.</p><p><strong>Eingabebefehl</strong>:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Rufen Sie den profile-Modus des supermemory-Tools auf, um zu sehen, was Sie über mich wissen</span></span></code></pre></div><p><strong>Was Sie sehen sollten</strong>: Zwei Arten von Informationen werden zurückgegeben:</p><ul><li><strong>Static</strong>: Statische Fakten (z. B. &quot;Benutzer ist Full-Stack-Ingenieur&quot;)</li><li><strong>Dynamic</strong>: Dynamische Präferenzen (z. B. &quot;Benutzer beschäftigt sich kürzlich mit Rust&quot;)</li></ul><h3 id="_4-audit-und-vergessen-list-forget" tabindex="-1">4. Audit und Vergessen (List &amp; Forget) <a class="header-anchor" href="#_4-audit-und-vergessen-list-forget" aria-label="Permalink to &quot;4. Audit und Vergessen (List &amp; Forget)&quot;">​</a></h3><p>Wenn der Agent fehlerhafte Informationen gespeichert hat (z. B. einen veralteten API Key), müssen Sie ihn löschen.</p><p><strong>Erster Schritt: Letzte Speicher auflisten</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Listen Sie die letzten 5 Projektspeicher auf</span></span></code></pre></div><p><em>(Agent ruft <code>mode: &quot;list&quot;, limit: 5</code> auf)</em></p><p><strong>Zweiter Schritt: ID abrufen und löschen</strong> Angenommen, Sie sehen einen fehlerhaften Speicher mit der ID <code>mem_abc123</code>.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Löschen Sie den Speicher mit der ID mem_abc123</span></span></code></pre></div><p><em>(Agent ruft <code>mode: &quot;forget&quot;, memoryId: &quot;mem_abc123&quot;</code> auf)</em></p><p><strong>Was Sie sehen sollten</strong>:</p><blockquote><p>✅ Memory mem_abc123 removed from project scope</p></blockquote><h2 id="fortgeschritten-auslosung-durch-naturliche-sprache" tabindex="-1">Fortgeschritten: Auslösung durch natürliche Sprache <a class="header-anchor" href="#fortgeschritten-auslosung-durch-naturliche-sprache" aria-label="Permalink to &quot;Fortgeschritten: Auslösung durch natürliche Sprache&quot;">​</a></h2><p>Sie müssen nicht jedes Mal Tool-Parameter detailliert beschreiben. Das Plugin verfügt über einen Schlüsselworterkennungsmechanismus.</p><p><strong>Probieren Sie es aus</strong>: Sagen Sie direkt im Dialog:</p><blockquote><p><strong>Remember this</strong>: Alle Datumsbearbeitungen müssen die Bibliothek date-fns verwenden, die Verwendung von moment.js ist verboten.</p></blockquote><p><strong>Was passiert?</strong></p><ol><li>Der <code>chat.message</code>-Hook des Plugins erkennt das Schlüsselwort &quot;Remember this&quot;.</li><li>Das Plugin injiziert einen System-Hinweis an den Agenten: <code>[MEMORY TRIGGER DETECTED]</code>.</li><li>Der Agent erhält die Anweisung: &quot;You MUST use the supermemory tool with mode: &#39;add&#39;...&quot;.</li><li>Der Agent extrahiert automatisch den Inhalt und ruft das Tool auf.</li></ol><p>Dies ist eine sehr natürliche Interaktionsweise, die es Ihnen ermöglicht, Wissen im Codierungsprozess jederzeit zu &quot;festigen&quot;.</p><h2 id="haufige-fragen-faq" tabindex="-1">Häufige Fragen (FAQ) <a class="header-anchor" href="#haufige-fragen-faq" aria-label="Permalink to &quot;Häufige Fragen (FAQ)&quot;">​</a></h2><p><strong>F: Was ist der Standard von <code>scope</code>?</strong> A: Der Standard ist <code>project</code>. Wenn Sie projektübergreifende allgemeine Präferenzen speichern möchten (z. B. &quot;Ich verwende immer TypeScript&quot;), geben Sie explizit <code>scope: &quot;user&quot;</code> an.</p><p><strong>F: Warum werden hinzugefügte Speicher nicht sofort wirksam?</strong> A: Die <code>add</code>-Operation ist asynchron. Normalerweise &quot;weiß&quot; der Agent sofort nach erfolgreichem Tool-Aufruf diesen neuen Speicher, aber bei extremen Netzwerkverzögerungen kann es ein paar Sekunden dauern.</p><p><strong>F: Werden sensible Informationen hochgeladen?</strong> A: Das Plugin maskiert automatisch den Inhalt innerhalb von <code>&lt;private&gt;</code>-Tags. Um sicher zu sein, empfehle ich jedoch, keine Passwörter oder API-Keys in Speicher zu legen.</p><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie, um die Quellcodepositionen anzuzeigen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Schlüsselworterkennung</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L34-L37" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>34-37</td></tr><tr><td>Auslöseprompt</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L20-L28" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>20-28</td></tr><tr><td>Client-Implementierung</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/services/client.ts" target="_blank" rel="noreferrer"><code>src/services/client.ts</code></a></td><td>Vollständiger Text</td></tr></tbody></table><p><strong>Wichtige Typdefinitionen</strong>:</p><ul><li><code>MemoryType</code>: Definiert in <a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/types/index.ts" target="_blank" rel="noreferrer"><code>src/types/index.ts</code></a></li><li><code>MemoryScope</code>: Definiert in <a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/types/index.ts" target="_blank" rel="noreferrer"><code>src/types/index.ts</code></a></li></ul></details><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../memory-management/">Speicherumfang und Lebenszyklus</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Der zugrundeliegende Isolationsmechanismus von User Scope und Project Scope</li><li>Wie man eine effiziente Speicherpartitionsstrategie entwirft</li><li>Lebenszyklusmanagement von Speichern</li></ul></blockquote>`,63)])])}const g=n(r,[["render",a]]);export{u as __pageData,g as default};
